            throw new IllegalArgumentException("用户名和模板内容不能为空 (Username and template content must not be blank)");
        }

        Template template = getOrCompileTemplate(templateContent);

        Map<String, Object> dataModel = Collections.singletonMap("username", username);

        StringWriter writer = new StringWriter(Math.max(128, templateContent.length() + 64));
