            return cached;
        }
        try {
            // 使用内容hash生成模板名以便定位问题
            String templateName = "userProfile:" + Integer.toHexString(templateContent.hashCode());
            Template compiled = new Template(templateName, templateContent, freemarkerConfig);
            templateCache.put(templateContent, compiled);
            return compiled;
        } catch (IOException e) {
            String msg = "模板编译失败 (Template compilation failed): " + e.getMessage();
            throw new RuntimeException(msg, e);
        }
    }
}

